// Map a GitHub Issue payload to a Vikunja task creation request.
//
// Configure the repo→project map below. Keys are GitHub `full_name`
// (org/repo). Values are Vikunja project IDs.
//
// You can also pass `?project=<id>` as a query string on the webhook URL
// to override the mapping per-hook.
const REPO_TO_PROJECT = {
  // 'CodeDredd/DreamServer': 1,
  // 'CodeDredd/openclaw': 2,
};
const DEFAULT_PROJECT_ID = parseInt($env.VIKUNJA_DEFAULT_PROJECT_ID || '1', 10);

const body = $input.first().json.body || $input.first().json;
const query = $input.first().json.query || {};
const issue = body.issue;
const action = body.action;
if (!issue) { throw new Error('Payload has no `issue` — is this a GitHub issue webhook?'); }
if (action !== 'opened' && action !== 'reopened') {
  // Skip — only react to new/reopened issues. Other workflows handle close.
  return [{ json: { skipped: true, action } }];
}

const repo = (body.repository && body.repository.full_name) || '';
const projectId = parseInt(query.project || REPO_TO_PROJECT[repo] || DEFAULT_PROJECT_ID, 10);

const labels = (issue.labels || []).map(l => l.name).filter(Boolean);
const description = [
  `**GitHub Issue:** ${issue.html_url}`,
  '',
  `**Repo:** ${repo}`,
  `**Author:** @${(issue.user && issue.user.login) || 'unknown'}`,
  labels.length ? `**Labels:** ${labels.map(l => `\`${l}\``).join(', ')}` : '',
  '',
  '---',
  '',
  issue.body || '_(no description)_',
].filter(Boolean).join('\n');

return [{
  json: {
    project_id: projectId,
    task: {
      title: `[${repo.split('/').pop() || 'issue'}] ${issue.title}`,
      description,
    },
    _meta: { issue_url: issue.html_url, issue_number: issue.number, repo },
  },
}];
